const nl = String.fromCharCode(10);
const body = items[0].json.body ?? items[0].json;
const lead = body.lead ?? body;
const maxReminders = 3;
const intervalMinutes = 10;
const vehicle = lead.vehicle ?? {};
const customer = lead.customer ?? {};
const budget = lead.budget ?? {};
const displayNumber = lead.lead_number ?? lead.leadNumber ?? 'AIC-000000';
const vehicleSummary = vehicle.summary ?? [vehicle.brand, vehicle.model, vehicle.year].filter(Boolean).join(' ');
const adminUrl = lead.admin_lead_url ?? lead.adminLeadUrl ?? '';
const name = customer.name ?? lead.customerName ?? '';
const phone = customer.phone ?? lead.phone ?? '';
const telegram = customer.telegram ?? lead.telegram ?? '';
const text = [
  'Новая заявка ' + displayNumber,
  '',
  'Клиент: ' + (name || 'Не указан'),
  'Телефон: ' + (phone || 'Не указан'),
  telegram ? 'Telegram: ' + telegram : 'Telegram: Не указан',
  '',
  'Авто: ' + (vehicleSummary || 'Не указано'),
  'Бюджет: ' + (budget.budget_rub ?? 'не указан') + ' ₽',
  'Итог: ' + (budget.total_rub ?? 'не указан') + ' ₽',
  adminUrl ? '' : null,
  adminUrl ? 'Открыть заявку: ' + adminUrl : null,
].filter((line) => line !== null).join(nl);

return [{
  json: {
    lead_id: lead.lead_id ?? lead.id,
    lead_number: displayNumber,
    customer_name: name,
    customer_phone: phone,
    customer_telegram: telegram,
    vehicle_summary: vehicleSummary,
    budget_rub: budget.budget_rub ?? null,
    total_rub: budget.total_rub ?? null,
    budget_status: budget.status ?? null,
    admin_lead_url: adminUrl,
    created_at: lead.created_at ?? new Date().toISOString(),
    reminder_count: 0,
    max_reminders: Number.isFinite(maxReminders) ? maxReminders : 3,
    reminder_interval_minutes: Number.isFinite(intervalMinutes) ? intervalMinutes : 10,
    telegram_message: text,
  },
}];

const state = $('Wait Reminder Interval').first().json;
const response = items[0].json;
const lead = response.lead ?? {};
const status = lead.status ?? 'unknown';
const reminderCount = Number(state.reminder_count ?? 0);
const maxReminders = Number(state.max_reminders ?? 3);
const createdAt = new Date(lead.createdAt ?? state.created_at ?? Date.now()).getTime();
const elapsedMinutes = Math.max(0, Math.round((Date.now() - createdAt) / 60000));
const displayNumber = lead.displayNumber ?? state.lead_number ?? 'AIC-000000';
const customerName = lead.customerName ?? state.customer_name ?? 'Не указан';
const phone = lead.phone ?? state.customer_phone ?? 'Не указан';
const vehicleSummary = lead.vehicleSummary ?? state.vehicle_summary ?? 'Не указано';
const adminUrl = state.admin_lead_url ?? '';
const base = {
  ...state,
  current_status: status,
  elapsed_minutes: elapsedMinutes,
  reminder_count: reminderCount,
};

if (status !== 'new') {
  return [{ json: { ...base, action: 'stop' } }];
}

if (reminderCount >= maxReminders) {
  return [{
    json: {
      ...base,
      action: 'red_alert',
      telegram_message: [
        `RED ALERT: заявка ${displayNumber} без реакции`,
        '',
        `Клиент: ${customerName}`,
        `Телефон: ${phone}`,
        `Авто: ${vehicleSummary}`,
        `Прошло минут: ${elapsedMinutes}`,
        adminUrl ? '' : null,
        adminUrl ? `Открыть заявку: ${adminUrl}` : null,
      ].filter((line) => line !== null).join('\n'),
    },
  }];
}

return [{
  json: {
    ...base,
    action: 'remind',
    telegram_message: [
      `Напоминание: заявка ${displayNumber} все еще новая`,
      '',
      `Клиент: ${customerName}`,
      `Телефон: ${phone}`,
      `Авто: ${vehicleSummary}`,
      `Напоминание: ${reminderCount + 1}/${maxReminders}`,
      adminUrl ? '' : null,
      adminUrl ? `Открыть заявку: ${adminUrl}` : null,
    ].filter((line) => line !== null).join('\n'),
  },
}];

const nl = String.fromCharCode(10);
const state = $('If Reminder').first().json;
const reminderCount = Number(state.reminder_count ?? 0) + 1;
const maxReminders = Number(state.max_reminders ?? 3);
const adminUrl = state.admin_lead_url ?? '';
const nextState = {
  ...state,
  reminder_count: reminderCount,
  reminder_interval_minutes: Number(state.reminder_interval_minutes ?? 10),
};

if (reminderCount >= maxReminders) {
  return [{ json: { ...nextState, action: 'red_alert', telegram_message: [
    'RED ALERT: заявка ' + (state.lead_number ?? 'AIC-000000') + ' без реакции',
    '',
    'Клиент: ' + (state.customer_name || 'Не указан'),
    'Телефон: ' + (state.customer_phone || 'Не указан'),
    'Авто: ' + (state.vehicle_summary || 'Не указано'),
    'Напоминаний отправлено: ' + reminderCount + '/' + maxReminders,
    adminUrl ? '' : null,
    adminUrl ? 'Открыть заявку: ' + adminUrl : null,
  ].filter((line) => line !== null).join(nl) } }];
}

return [{ json: { ...nextState, action: 'wait_next_reminder' } }];
